  {"qe":"The Bhoodan Movement was started by?","qh":"भूदान आंदोलन किसने शुरू किया?","opts":["Vinoba Bhave","Jay Prakash Narayan","Gandhi Ji","Nehru Ji"],"ans":0,"exp":"Vinoba Bhave started Bhoodan (land gift) Movement in 1951 — requested landlords to donate land.","diff":"medium"},
  {"qe":"The Khilafat Movement was related to?","qh":"खिलाफत आंदोलन किससे संबंधित था?","opts":["Salt tax","Defense of Ottoman Caliphate (Turkey)","Hindu-Muslim unity only","Anti-partition campaign"],"ans":1,"exp":"Khilafat Movement (1919-24) protested against treatment of Ottoman Caliphate by British after WWI.","diff":"medium"},
  {"qe":"The Great Stupa at Sanchi was originally built by?","qh":"साँची का महास्तूप किसने बनवाया?","opts":["Ashoka","Chandragupta","Kanishka","Samudragupta"],"ans":0,"exp":"Emperor Ashoka built the original Great Stupa at Sanchi in the 3rd century BC.","diff":"medium"},
