  {"qe":"Right to Education (RTE) Act was passed in?","qh":"शिक्षा का अधिकार अधिनियम कब पारित हुआ?","opts":["2005","2007","2009","2010"],"ans":2,"exp":"Right to Education Act 2009 — free and compulsory education for children aged 6-14 years.","diff":"medium"},
  {"qe":"The concept of 'Preamble' was borrowed from?","qh":"'प्रस्तावना' की अवधारणा कहाँ से ली गई?","opts":["UK","USA","Canada","Ireland"],"ans":1,"exp":"The Preamble was borrowed from the Constitution of the United States of America.","diff":"medium"},
  {"qe":"Who is the guardian of the Constitution?","qh":"संविधान का संरक्षक कौन है?","opts":["President","Parliament","Supreme Court","Attorney General"],"ans":2,"exp":"Supreme Court of India is the guardian/custodian of the Constitution through judicial review.","diff":"easy"},
  {"qe":"The number of subjects in the Union List?","qh":"संघ सूची में विषयों की संख्या?","opts":["66","97","61","52"],"ans":1,"exp":"Union List (Schedule 7) has 97 subjects (originally 97, now considered 100).","diff":"medium"},
  {"qe":"The Emergency provisions are in which article?","qh":"आपातकाल के प्रावधान किस अनुच्छेद में?","opts":["Article 352","Article 360","Article 356","All of these"],"ans":3,"exp":"National Emergency: Art 352; State Emergency: Art 356; Financial Emergency: Art 360.","diff":"medium"},
  {"qe":"The Rajya Sabha is a permanent body because?","qh":"राज्यसभा स्थायी सदन है क्योंकि?","opts":["President cannot dissolve it","It has unlimited members","Only elected body","PM cannot dissolve it"],"ans":0,"exp":"Rajya Sabha cannot be dissolved by President — only Lok Sabha can be dissolved. 1/3 members retire every 2 years.","diff":"medium"},
