  {"qe":"Which Schedule of Constitution contains languages?","qh":"भाषाओं की सूची किस अनुसूची में?","opts":["6th","7th","8th","9th"],"ans":2,"exp":"8th Schedule of Indian Constitution lists 22 officially recognized languages.","diff":"medium"},
  {"qe":"The concept of Judicial Review was taken from?","qh":"न्यायिक समीक्षा की अवधारणा कहाँ से ली गई?","opts":["UK","France","USA","Canada"],"ans":2,"exp":"Judicial Review was borrowed from the USA where judiciary can declare laws unconstitutional.","diff":"medium"},
  {"qe":"Zero Hour in Parliament starts at?","qh":"संसद में 'शून्य काल' कब शुरू होता है?","opts":["9 AM","11 AM","12 Noon","2 PM"],"ans":2,"exp":"Zero Hour starts at 12 noon in Parliament — members raise urgent matters without advance notice.","diff":"medium"},
  {"qe":"The President of India is elected by?","qh":"भारत के राष्ट्रपति का चुनाव कौन करता है?","opts":["All citizens","Only Lok Sabha","Elected members of Parliament + State Assemblies","All Parliament members"],"ans":2,"exp":"President is elected by elected members of both Houses of Parliament + elected members of State Legislative Assemblies (Article 54).","diff":"medium"},
  {"qe":"Which article abolishes untouchability?","qh":"अस्पृश्यता समाप्त करने का अनुच्छेद?","opts":["Article 15","Article 16","Article 17","Article 18"],"ans":2,"exp":"Article 17 abolishes 'untouchability' and its practice is a punishable offence.","diff":"medium"},
  {"qe":"The term of Rajya Sabha members is?","qh":"राज्यसभा सदस्यों का कार्यकाल?","opts":["4 years","5 years","6 years","7 years"],"ans":2,"exp":"Rajya Sabha members serve for 6 years. 1/3 retire every 2 years.","diff":"easy"},
  {"qe":"The Finance Commission is constituted under Article?","qh":"वित्त आयोग किस अनुच्छेद के तहत?","opts":["Article 280","Article 360","Article 324","Article 148"],"ans":0,"exp":"Finance Commission is constituted under Article 280 every 5 years to recommend tax devolution.","diff":"medium"},
  {"qe":"Which country's constitution inspired India's Fundamental Duties?","qh":"मौलिक कर्तव्य किस देश के संविधान से प्रेरित?","opts":["USA","UK","USSR (Russia)","France"],"ans":2,"exp":"Fundamental Duties (Article 51A) added by 42nd Amendment (1976) — inspired by USSR Constitution.","diff":"medium"},
  {"qe":"The Election Commission is established under Article?","qh":"निर्वाचन आयोग किस अनुच्छेद के तहत?","opts":["Article 280","Article 312","Article 324","Article 356"],"ans":2,"exp":"Election Commission of India (independent body) is established under Article 324.","diff":"medium"},
  {"qe":"Concurrent List subjects can be legislated by?","qh":"समवर्ती सूची के विषयों पर कानून बना सकते हैं?","opts":["Only Centre","Only States","Both Centre and States","Judiciary"],"ans":2,"exp":"Both Centre and States can legislate on Concurrent List subjects. In conflict, Centre's law prevails.","diff":"easy"},
  {"qe":"Who administers oath to the President?","qh":"राष्ट्रपति को शपथ कौन दिलाता है?","opts":["PM","Speaker","Chief Justice of India","Vice President"],"ans":2,"exp":"Chief Justice of India (or senior Supreme Court judge) administers oath to the President.","diff":"medium"},
  {"qe":"Money Bill can be introduced in?","qh":"धन विधेयक कहाँ पेश किया जा सकता है?","opts":["Either House","Rajya Sabha only","Lok Sabha only","Joint Session only"],"ans":2,"exp":"Money Bill (Article 110) can only be introduced in Lok Sabha, not Rajya Sabha.","diff":"easy"},
  {"qe":"The 73rd Constitutional Amendment deals with?","qh":"73वाँ संविधान संशोधन किससे संबंधित है?","opts":["Right to Education","Panchayati Raj","Urban local bodies","Fundamental Duties"],"ans":1,"exp":"73rd Amendment (1992) gave constitutional status to Panchayati Raj institutions (rural local governance).","diff":"medium"},
  {"qe":"The Comptroller and Auditor General (CAG) is appointed by?","qh":"CAG की नियुक्ति कौन करता है?","opts":["PM","Parliament","President","Finance Minister"],"ans":2,"exp":"CAG is appointed by the President of India — reports to Parliament on government accounts.","diff":"medium"},
  {"qe":"Which writ is issued to produce a person before the court?","qh":"व्यक्ति को न्यायालय में पेश करने के लिए कौन सी रिट?","opts":["Mandamus","Certiorari","Habeas Corpus","Quo Warranto"],"ans":2,"exp":"Habeas Corpus = 'you shall have the body' — writ to bring detained person before court.","diff":"medium"},
  {"qe":"The Preamble declares India to be?","qh":"प्रस्तावना भारत को क्या घोषित करती है?","opts":["Federal Republic","Sovereign Democratic Republic","Sovereign Socialist Secular Democratic Republic","Democratic Secular Republic"],"ans":2,"exp":"Preamble: Sovereign, Socialist, Secular, Democratic, Republic (as amended by 42nd Amendment 1976).","diff":"medium"},
  {"qe":"Chief Minister is appointed by?","qh":"मुख्यमंत्री की नियुक्ति कौन करता है?","opts":["President","PM","Governor","Vidhan Sabha Speaker"],"ans":2,"exp":"Chief Minister is appointed by the Governor of the state (Article 164) — leader of majority party.","diff":"easy"},
  {"qe":"The concept of 5-year plan was borrowed from?","qh":"पंचवर्षीय योजना की अवधारणा कहाँ से ली गई?","opts":["USA","UK","USSR","China"],"ans":2,"exp":"Five-Year Plans were inspired by Soviet Union's (USSR) centralized planning model.","diff":"medium"},
